from typing import Any

def get_customer_record(customer_id: str) -> dict[str, Any]:
    """Fetch a customer record from the internal CRM."""
    if not customer_id.isalnum() or len(customer_id) > 64:
        return {"error": "VALIDATION_ERROR",
                "message": "customer_id must be alphanumeric, max 64 chars"}

    resp = _SESSION.get(
        f"{_INTERNAL_BASE}/crm/customers/{customer_id}",
        timeout=8,
    )
    if resp.status_code == 404:
        return {"error": "NOT_FOUND",
                "message": f"No customer with id={customer_id}"}
    if resp.status_code == 403:
        return {"error": "PERMISSION_DENIED",
                "message": "Agent service account lacks read access to CRM"}
    if not resp.ok:
        return {"error": "SERVICE_UNAVAILABLE",
                "message": f"CRM returned {resp.status_code}"}

    c = resp.json()
    # Prune: return only what the model needs; omit PII like SSN, date of birth
    return {
        "customer_id":   c["id"],
        "account_name":  c["name"],
        "tier":          c.get("tier", "standard"),
        "status":        c["status"],          # active | suspended | closed
        "open_tickets":  c.get("open_tickets", 0),
        "account_manager": c.get("account_manager_name"),
        "created_at":    c["created_at"],
    }

_WRITABLE_STATUS = {"active", "suspended"}

def update_account_status(
    customer_id: str,
    new_status: str,
    reason: str,
) -> dict[str, Any]:
    """Update a customer account status (active or suspended only)."""
    if not customer_id.isalnum() or len(customer_id) > 64:
        return {"error": "VALIDATION_ERROR",
                "message": "customer_id must be alphanumeric, max 64 chars"}
    if new_status not in _WRITABLE_STATUS:
        return {"error": "VALIDATION_ERROR",
                "message": f"new_status must be one of {sorted(_WRITABLE_STATUS)}"}
    reason = reason.strip()
    if len(reason) < 10:
        return {"error": "VALIDATION_ERROR",
                "message": "reason must be at least 10 characters"}

    resp = _SESSION.patch(
        f"{_INTERNAL_BASE}/crm/customers/{customer_id}",
        json={"status": new_status, "change_reason": reason},
        timeout=10,
    )
    if resp.status_code == 404:
        return {"error": "NOT_FOUND", "message": f"No customer with id={customer_id}"}
    if resp.status_code == 403:
        return {"error": "PERMISSION_DENIED",
                "message": "Agent service account lacks write access to CRM"}
    if resp.status_code == 409:
        return {"error": "CONFLICT",
                "message": "Account is already in the requested status"}
    if not resp.ok:
        return {"error": "SERVICE_UNAVAILABLE",
                "message": f"CRM returned {resp.status_code}"}

    updated = resp.json()
    return {
        "customer_id": updated["id"],
        "status":      updated["status"],
        "updated_at":  updated["updated_at"],
    }

from google.cloud import bigquery

_BQ = bigquery.Client()   # uses Application Default Credentials / Workload Identity
_PROJECT = os.environ["GCP_PROJECT"]
_DATASET = "analytics"

def get_revenue_by_product(
    product_id: str,
    start_date: str,   # YYYY-MM-DD
    end_date: str,
) -> dict[str, Any]:
    """Return total revenue for a product in a date range."""
    import re
    DATE_RE = re.compile(r"^\d{4}-\d{2}-\d{2}$")
    if not DATE_RE.match(start_date) or not DATE_RE.match(end_date):
        return {"error": "VALIDATION_ERROR",
                "message": "dates must be YYYY-MM-DD"}
    if start_date > end_date:
        return {"error": "VALIDATION_ERROR",
                "message": "start_date must be on or before end_date"}

    query = f"""
        SELECT
            product_id,
            SUM(revenue_usd) AS total_revenue_usd,
            COUNT(DISTINCT order_id) AS order_count
        FROM `{_PROJECT}.{_DATASET}.orders`
        WHERE product_id = @product_id
          AND DATE(created_at) BETWEEN @start_date AND @end_date
        GROUP BY product_id
    """
    job_config = bigquery.QueryJobConfig(
        query_parameters=[
            bigquery.ScalarQueryParameter("product_id", "STRING", product_id),
            bigquery.ScalarQueryParameter("start_date", "DATE", start_date),
            bigquery.ScalarQueryParameter("end_date", "DATE", end_date),
        ]
    )
    rows = list(_BQ.query(query, job_config=job_config).result())
    if not rows:
        return {"error": "NOT_FOUND",
                "message": f"No revenue data for product_id={product_id} in range"}
    row = rows[0]
    return {
        "product_id":        row.product_id,
        "total_revenue_usd": float(row.total_revenue_usd),
        "order_count":       row.order_count,
        "start_date":        start_date,
        "end_date":          end_date,
    }

import boto3, json, uuid
from datetime import datetime, timezone

_SQS = boto3.client("sqs", region_name=os.environ["AWS_REGION"])
_QUEUE_URL = os.environ["AGENT_EVENTS_QUEUE_URL"]

def enqueue_account_review(
    customer_id: str,
    priority: str,
    notes: str,
) -> dict[str, Any]:
    """Submit a customer account for human review via the internal queue."""
    if priority not in ("low", "medium", "high"):
        return {"error": "VALIDATION_ERROR",
                "message": "priority must be low, medium, or high"}
    notes = notes.strip()
    if not notes:
        return {"error": "VALIDATION_ERROR", "message": "notes are required"}

    event = {
        "event_type":  "account_review_requested",
        "customer_id": customer_id,
        "priority":    priority,
        "notes":       notes[:1000],
        "requested_by": "support-agent-v1",
        "request_id":   str(uuid.uuid4()),
        "timestamp":    datetime.now(timezone.utc).isoformat(),
    }
    try:
        resp = _SQS.send_message(
            QueueUrl=_QUEUE_URL,
            MessageBody=json.dumps(event),
            MessageDeduplicationId=event["request_id"],  # for FIFO queues
            MessageGroupId="account-reviews",
        )
    except Exception as exc:
        return {"error": "SERVICE_UNAVAILABLE",
                "message": f"Failed to enqueue: {exc}"}

    return {
        "queued":     True,
        "request_id": event["request_id"],
        "message_id": resp["MessageId"],
    }

import time
from dataclasses import dataclass, field

@dataclass
class CircuitBreaker:
    failure_threshold: int = 5
    recovery_seconds: float = 30.0
    _failures: int = field(default=0, repr=False)
    _opened_at: float | None = field(default=None, repr=False)

    def is_open(self) -> bool:
        if self._opened_at is None:
            return False
        if time.monotonic() - self._opened_at > self.recovery_seconds:
            self._failures = 0
            self._opened_at = None
            return False
        return True

    def record_failure(self) -> None:
        self._failures += 1
        if self._failures >= self.failure_threshold:
            self._opened_at = time.monotonic()

    def record_success(self) -> None:
        self._failures = 0
        self._opened_at = None

_CRM_BREAKER = CircuitBreaker()

def _crm_get(path: str, **kwargs) -> requests.Response:
    if _CRM_BREAKER.is_open():
        raise RuntimeError("CRM circuit breaker is open — service unavailable")
    try:
        resp = _SESSION.get(f"{_INTERNAL_BASE}{path}", **kwargs)
        if resp.ok:
            _CRM_BREAKER.record_success()
        elif resp.status_code >= 500:
            _CRM_BREAKER.record_failure()
        return resp
    except Exception:
        _CRM_BREAKER.record_failure()
        raise
